        "path": "src/components/ui/Button/button.tsx",
        "content": "import { forwardRef } from \"react\";\r\nimport type { ButtonProps } from \"./button.types\";\r\nimport { buttonVariants } from \"./button.styles\";\r\n\r\nexport const Button = forwardRef<HTMLButtonElement, ButtonProps>(\r\n  function Button(\r\n    {\r\n      color,\r\n      variant,\r\n      size,\r\n      shape,\r\n      fullWidth,\r\n      loading = false,\r\n      disabled = false,\r\n      iconLeft,\r\n      iconRight,\r\n      children,\r\n      className,\r\n      type = \"button\",\r\n      ...rest\r\n    },\r\n    ref,\r\n  ) {\r\n    const isDisabled = disabled || loading;\r\n\r\n    return (\r\n      <button\r\n        ref={ref}\r\n        type={type}\r\n        disabled={isDisabled}\r\n        className={buttonVariants({\r\n          color,\r\n          variant,\r\n          size,\r\n          shape,\r\n          fullWidth,\r\n          disabled: isDisabled,\r\n          className,\r\n        })}\r\n        {...rest}\r\n      >\r\n        {loading && <Spinner />}\r\n        {!loading && iconLeft}\r\n        {children}\r\n        {!loading && iconRight}\r\n      </button>\r\n    );\r\n  },\r\n);\r\n\r\nfunction Spinner() {\r\n  return (\r\n    <svg\r\n      width=\"16\"\r\n      height=\"16\"\r\n      viewBox=\"0 0 16 16\"\r\n      fill=\"none\"\r\n      className=\"animate-spin\"\r\n    >\r\n      <circle\r\n        cx=\"8\"\r\n        cy=\"8\"\r\n        r=\"6\"\r\n        stroke=\"currentColor\"\r\n        strokeWidth=\"2\"\r\n        strokeLinecap=\"round\"\r\n        strokeDasharray=\"28\"\r\n        strokeDashoffset=\"8\"\r\n        className=\"opacity-70\"\r\n      />\r\n    </svg>\r\n  );\r\n}\r\n",
